# ── Game HTML templates ──
def G_REVEAL(btn_text, hidden_html):
    return f'<div class="mg-reveal" data-mg="reveal"><button class="mg-btn">💡 {btn_text}</button><div class="mg-body">{hidden_html}</div></div>'

def G_QUIZ(question, opts, correct_idx, right_msg, wrong_msg):
    labels = ['🅰️', '🅱️']
    btns = ''.join(f'<button class="mg-btn">{labels[i] if i < len(labels) else ""} {o}</button>' for i,o in enumerate(opts))
    return f'<div class="mg-quiz" data-mg="quiz" data-correct="{correct_idx}" data-right="{right_msg}" data-wrong="{wrong_msg}"><p style="font-size:12px;color:var(--tx2);margin-bottom:4px">🤔 {question}</p>{btns}<span class="mg-feedback"></span></div>'

def G_FLIP(front, back):
    return f'<div class="mg-flip" data-mg="flip"><div class="mg-flip-inner"><div class="mg-front">{front}</div><div class="mg-back">{back}</div></div></div>'

def G_SLIDER(stops):
    n = len(stops) - 1
    return f'<div class="mg-slider" data-mg="slider" data-stops=\'{json.dumps(stops)}\'><input type="range" min="0" max="{n}" value="{n//2}"><div class="mg-slider-label"></div></div>'

def G_MATCH(pairs, left_labels, right_labels):
    left = ''.join(f'<div class="mg-opt" data-idx="{i}">{l}</div>' for i,l in enumerate(left_labels))
    right = ''.join(f'<div class="mg-opt" data-idx="{i}">{r}</div>' for i,r in enumerate(right_labels))
    return f'<div class="mg-match" data-mg="match" data-pairs=\'{json.dumps(pairs)}\'><div class="mg-match-l">{left}</div><div class="mg-match-r">{right}</div><div class="mg-match-msg"></div></div>'

def G_SCENARIO(prompt, choices, outcomes):
    btns = ''.join(f'<button class="mg-btn" data-outcome="{o}">{c}</button>' for c,o in zip(choices, outcomes))
    return f'<div class="mg-scenario" data-mg="scenario"><p style="font-size:12px;color:var(--tx2);margin-bottom:4px">{prompt}</p>{btns}<div class="mg-outcome"></div></div>'

def G_COUNTER(steps):
    return f'<div class="mg-counter" data-mg="counter" data-steps=\'{json.dumps(steps)}\'><button class="mg-btn">+1</button><span class="mg-count">0</span><div class="mg-msg">{steps.get("0","开始点击")}</div></div>'

def G_SORT(categories, items):
    btns = ''.join(f'<button class="mg-btn">{c}</button>' for c in categories)
    return f'<div class="mg-sort" data-mg="sort" data-categories=\'{json.dumps(categories)}\' data-items=\'{json.dumps(items)}\'><div class="mg-sort-q"></div><div class="mg-sort-btns">{btns}</div><div class="mg-sort-score"></div></div>'

# ── NEW: 4-option quiz with explanations ──
def G_QUIZ4(question, options, correct_idx, explains):
    """options: list of 4 strings. correct_idx: 0-3. explains: list of 4 strings (shown after selection)."""
    labels = ['🅰️', '🅱️', '©️', '🅳']
    btns = ''.join(f'<button class="mg-q4-opt">{labels[i]} {options[i]}</button>' for i in range(len(options)))
    explains_json = json.dumps(explains, ensure_ascii=False)
    return f'<div class="mg-quiz4" data-mg="quiz4" data-correct="{correct_idx}" data-explains=\'{explains_json}\'><div class="mg-q4-header"><p class="mg-q4-q">🤔 {question}</p><span class="mg-q4-counter"></span></div>{btns}<div class="mg-q4-explain"></div></div>'

# ── NEW: Likert self-assessment ──
def G_SCALE(items, profiles):
    """items: list of {q, low, high}. profiles: dict {min_score: label}."""
    rows = ''
    for i, item in enumerate(items):
        row = f'<div class="mg-scale-row" data-idx="{i}"><span class="mg-scale-q">{item["q"]}</span><div class="mg-scale-btns">'
        for j in range(1,6):
            row += f'<button class="mg-scale-btn" data-v="{j}">{j}</button>'
        row += '</div></div>'
        rows += row
    return f'<div class="mg-scale" data-mg="scale" data-items=\'{json.dumps(items, ensure_ascii=False)}\' data-profiles=\'{json.dumps(profiles, ensure_ascii=False)}\'>{rows}<div class="mg-scale-score"></div><div class="mg-scale-result"></div></div>'

# ── NEW: Spot the bias among scenarios ──
def G_SPOT(instruction, items, label):
    """items: list of {text, has}. label: name of the bias to spot."""
    cards = ''
    for i, item in enumerate(items):
        cards += f'<div class="mg-spot-card" data-idx="{i}" data-has="{str(item["has"]).lower()}">{item["text"]}</div>'
    return f'<div class="mg-spot" data-mg="spot" data-label="{label}"><p class="mg-q4-q">🔍 {instruction}</p><div class="mg-spot-cards">{cards}</div><div class="mg-spot-fb"></div></div>'

# ── NEW: Experience trap ──
def G_TRAP(title, steps):
    """steps: list of {prompt, choices, labels, trap, correct, reveal}."""
    return f'<div class="mg-trap" data-mg="trap" data-title="{title}" data-steps=\'{json.dumps(steps, ensure_ascii=False)}\'><div class="mg-trap-step"></div><div class="mg-trap-prompt"></div><div class="mg-trap-choices"></div><div class="mg-trap-reveal"></div></div>'

