# ── Injection logic ──
def inject_games(filepath, games):
    """Inject game HTML, CSS, JS, and fix navigation in filepath. Idempotent."""
    with open(filepath, 'r', encoding='utf-8') as f:
        page = f.read()

    modified = False

    # 1. Inject game HTML into cards (skip if v3 marker present)
    if 'mini-games v3' not in page:
        game_map = {str(k): g for k, g in games}
        TAG = '<div class="card">'
        CARD_NUM_RE = re.compile(r'<span class="card-num">(\d+)</span>')
        BADGE_RE = re.compile(r'<span class="(?:type-badge|sleep-badge)[^"]*">([^<]+)</span>')
        result = []
        pos = 0

        while True:
            idx = page.find(TAG, pos)
            if idx == -1:
                result.append(page[pos:])
                break
            result.append(page[pos:idx])
            pos = idx
            depth = 0
            card_key = None
            i = pos
            card_start = pos
            while i < len(page):
                if page.startswith('<div', i):
                    depth += 1
                    i += 4
                elif page.startswith('</div>', i):
                    depth -= 1
                    if depth == 0:
                        card_body = page[card_start:i]
                        m = CARD_NUM_RE.search(card_body)
                        if m:
                            card_key = m.group(1)
                        else:
                            m = BADGE_RE.search(card_body)
                            if m:
                                card_key = html.unescape(m.group(1))
                        if card_key and card_key in game_map:
                            result.append(card_body + game_map[card_key] + '</div>')
                        else:
                            result.append(page[card_start:i+6])
                        pos = i + 6
                        break
                    i += 6
                else:
                    i += 1
        page = ''.join(result)
        modified = True

    # 2. Add GAME_CSS before </style>
    if GAME_CSS.strip() not in page:
        page = page.replace('</style>', GAME_CSS + '\n</style>')
        modified = True

    # 3. Add mini-games.js before </body>
    if 'mini-games.js' not in page:
        page = page.replace('</body>', '<script src="./mini-games.js"></script>\n</body>')
        modified = True

    # 4. Fix bottom-nav: add 首页 link if missing
    if 'bottom-nav' in page and '首页</a></div>' not in page and '首页</a>' not in page.split('bottom-nav')[1].split('</div>')[0]:
        page = page.replace(
            '百科</a></div>',
            '百科</a><a class="nav-btn" href="./index.html"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/></svg>首页</a></div>'
        )
        modified = True

    # 5. Fix header: add home button next to back button if missing
    if 'class="home-btn"' not in page and 'class="back-btn"' in page:
        # Add .home-btn CSS after .back-btn:hover rule
        if '.home-btn{' not in page:
            page = page.replace(
                '.back-btn:hover{background:rgba(255,255,255,.1);color:var(--tx)}',
                '.back-btn:hover{background:rgba(255,255,255,.1);color:var(--tx)}.home-btn{width:32px;height:32px;border-radius:8px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.08);display:flex;align-items:center;justify-content:center;cursor:pointer;color:var(--tx2);transition:all .3s var(--ease);flex-shrink:0;text-decoration:none;margin-left:auto}.home-btn:hover{background:rgba(255,255,255,.1);color:var(--tx)}'
            )
        # Add home button HTML after header-logo span
        HOME_BTN = '<a class="home-btn" href="./index.html" title="返回主页"><svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/></svg></a>'
        page = re.sub(
            r'(<span class="header-logo">[^<]*</span>)',
            r'\1' + HOME_BTN,
            page
        )
        modified = True

    if modified:
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(page)

    return filepath

# ── Puxing pages (21 pages, ~66 cards) ──
def _Q(question, options, correct_idx, right_msg, wrong_msg=None):
    """4-option quiz for puxing pages."""
    explains = ['']*4
    explains[correct_idx] = '🎯 ' + right_msg
    for i in range(4):
        if i != correct_idx:
            explains[i] = '📌 ' + (options[i] + ' —— 这不是最佳答案。' if i < len(options) else '')
    # Ensure wrong_msg is used if provided
    if wrong_msg:
        for i in range(4):
            if i != correct_idx and i == 0:
                explains[i] = '📌 ' + wrong_msg
    return G_QUIZ4(question, options, correct_idx, explains)

def _R(btn_text, answer):
    return G_REVEAL(btn_text, answer)

def _S(prompt, choices, outcomes):
    return G_SCENARIO(prompt, choices, outcomes)

